effect.shader:
float random (in vec2 st) {
    return fract(sin(dot(st.xy,
                         vec2(12.9898,78.233)))*
        43758.5453123);
}

// Based on Morgan McGuire @morgan3d
// https://www.shadertoy.com/view/4dS3Wd
float noise (vec2 st) {
    vec2 i = floor(st);
    vec2 f = fract(st);

    // Four corners in 2D of a tile
    float a = random(i);
    float b = random(i + vec2(1.0, 0.0));
    float c = random(i + vec2(0.0, 1.0));
    float d = random(i + vec2(1.0, 1.0));

    vec2 u = f * f * (3.0 - 2.0 * f);

    return mix(a, b, u.x) +
            (c - a)* u.y * (1.0 - u.x) +
            (d - b) * u.x * u.y;
}

float fbm (vec2 st, vec2 parallax, int octaveCount, float intens) {
    // Initial values
    float value = 0.;
    float amplitude = 0.5;
    float frequency = 0.;
    //
    // Loop of octaves
    for (int i = 0; i < octaveCount; i++) {
        value += amplitude * noise(st);
        st *= 2.0;
        st += parallax;
        amplitude *= intens;
    }
    return value;
}


vec2 rand2v(vec2 co) {
    return vec2(noise(co),noise(co+vec2(613.312,736.019)));
}

void main() {
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);

    vec2 st = acLayerNorm.st;
    st.x *= acLayerSize.x/acLayerSize.y;
    st -= vec2(0.5,0.5);

    st *= scale;

    vec2 tile = floor(st);
    vec2 tpart = fract(st);

    float maxDist = 100.0;
    vec2 nearestTile = vec2(0.0,0.0);
    vec2 nearestTileOffs = vec2(0.0,0.0);
    //float nearest_k = 0.;
    vec2 nearest_r = vec2(0.0,0.0);

    //int densitySteps = int(density);

    float actualPhase = phase * 6.28318;

    vec2 seedVec = vec2(123.215,272.055)*seed;

    for( int i=-1; i<=1; i++ ) {
        for( int j=-1; j<=1; j++ ) {
            vec2 checkTileOffs = vec2(float(i),float(j));
            //for( int k=0; k<densitySteps; k++ ) {
                vec2 p = rand2v(tile + checkTileOffs + seedVec);
                p = 0.5 + 0.5*sin(actualPhase + 6.2831*p);
                vec2 r = checkTileOffs + p - tpart;
                float dist = dot(r,r);
                if( dist < maxDist ) {
                    maxDist = dist;
                    //nearest_k = float(k);
                    nearest_r = r;
                    nearestTile = checkTileOffs + tile;
                    nearestTileOffs = checkTileOffs;
                }
            //}
        }
    }

    float actualMaxDist = 100.0;
    for( int i=-2; i<=2; i++ ) {
        for( int j=-2; j<=2; j++ ) {
            vec2 checkTileOffs = nearestTileOffs + vec2(float(i),float(j));
            //for( int k=0; k<densitySteps; k++ ) {
                vec2 p = rand2v(tile + checkTileOffs + seedVec);
                p = 0.5 + 0.5*sin(actualPhase + 6.2831*p);
                vec2 r = checkTileOffs + p - tpart;
                if( dot(nearest_r-r,nearest_r-r) > 0.00001 ) {
                    float dist = dot(0.5*(nearest_r+r), normalize(r-nearest_r));
                    actualMaxDist = min(dist,actualMaxDist);
                }
            //}
        }
    }

    //float colorPct =  random(nearestTile + vec2(nearest_k,-nearest_k) + vec2(721.117,433.215)*seed);
    float colorPct =  random(nearestTile + vec2(721.117,433.215)*seed);

    vec4 result = mix(color,color2,colorPct); // * actualMaxDist;

    vec4 line = lineWidth<0.00001 ? vec4(0.0) : lineColor * (1.0-smoothstep(lineWidth-0.02,lineWidth+0.001,actualMaxDist));

    //result = vec4(actualMaxDist,actualMaxDist,0.5,1.0);

    result = line + ((1.0-line.a)*result);

    result = result * texColor.a;

    gl_FragColor = result;
}
